module RefModule (
    input clk,
    input rst,
    input en,
    output [4:0] q
);

    reg [4:0] obf_q_reg;

    always @(posedge clk or posedge rst) begin
        if (rst)
            obf_q_reg <= 5'b0;
        else if (en)
            obf_q_reg <= obf_q_reg + 3;
    end

    assign q = obf_q_reg;

endmodule
